import{_ as a,o as i,c as t,a2 as e}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"1989年巴菲特致股东信核心要点","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1989年/核心总结.md","filePath":"01_letters/1989年/核心总结.md"}'),r={name:"01_letters/1989年/核心总结.md"};function o(h,l,u,n,d,s){return i(),t("div",null,[...l[0]||(l[0]=[e('<h1 id="_1989年巴菲特致股东信核心要点" tabindex="-1">1989年巴菲特致股东信核心要点 <a class="header-anchor" href="#_1989年巴菲特致股东信核心要点" aria-label="Permalink to &quot;1989年巴菲特致股东信核心要点&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>净资产增长15.15亿美元（44.4%）</li><li>每股账面价值从$19.46增长至$4,296.01</li><li>25年复合增长率：23.8%</li></ul><hr><h2 id="核心投资理念" tabindex="-1">核心投资理念 <a class="header-anchor" href="#核心投资理念" aria-label="Permalink to &quot;核心投资理念&quot;">​</a></h2><h3 id="_1-内在价值-vs-账面价值" tabindex="-1">1. 内在价值 vs 账面价值 <a class="header-anchor" href="#_1-内在价值-vs-账面价值" aria-label="Permalink to &quot;1. 内在价值 vs 账面价值&quot;">​</a></h3><ul><li>内在价值 = 未来所有现金流的折现现值</li><li>过去：账面价值高于内在价值（纺织业务拖累）</li><li>现在：内在价值远高于账面价值</li></ul><h3 id="_2-双重收益-时代的结束" tabindex="-1">2. &quot;双重收益&quot;时代的结束 <a class="header-anchor" href="#_2-双重收益-时代的结束" aria-label="Permalink to &quot;2. &quot;双重收益&quot;时代的结束&quot;">​</a></h3><ul><li>过去获得&quot;double dip&quot;： <ul><li>持仓公司内在价值增长</li><li>市场定价纠正（估值修复）</li></ul></li><li>未来只能获得&quot;single dip&quot;：业务增长本身</li><li>定价纠正已完成</li></ul><h3 id="_3-高增长的自我限制" tabindex="-1">3. 高增长的自我限制 <a class="header-anchor" href="#_3-高增长的自我限制" aria-label="Permalink to &quot;3. 高增长的自我限制&quot;">​</a></h3><ul><li>引用卡尔·萨根的细菌繁殖例子</li><li>高增长率必然自我毁灭</li><li>从49亿基数开始，15%增长比从2200万开始难太多</li></ul><hr><h2 id="零息债券创新" tabindex="-1">零息债券创新 <a class="header-anchor" href="#零息债券创新" aria-label="Permalink to &quot;零息债券创新&quot;">​</a></h2><h3 id="发行详情" tabindex="-1">发行详情 <a class="header-anchor" href="#发行详情" aria-label="Permalink to &quot;发行详情&quot;">​</a></h3><ul><li>发行9.02亿美元零息可转换债券</li><li>15年到期，年化收益率5.5%</li><li>转股价溢价15%</li></ul><h3 id="零息债券的优势" tabindex="-1">零息债券的优势 <a class="header-anchor" href="#零息债券的优势" aria-label="Permalink to &quot;零息债券的优势&quot;">​</a></h3><ul><li>递延税收优惠（每年可扣减利息，但无需现金支付）</li><li>正现金流</li><li>相当于政府提供无息贷款</li></ul><h3 id="对垃圾债零息债券的批评" tabindex="-1">对垃圾债零息债券的批评 <a class="header-anchor" href="#对垃圾债零息债券的批评" aria-label="Permalink to &quot;对垃圾债零息债券的批评&quot;">​</a></h3><ul><li>EBDIT（息税折旧前利润）是误导性指标</li><li>很多发行人本质无力支付利息</li><li>&quot;延迟付息&quot;不等于&quot;不需要付息&quot;</li></ul><hr><h2 id="税收策略" tabindex="-1">税收策略 <a class="header-anchor" href="#税收策略" aria-label="Permalink to &quot;税收策略&quot;">​</a></h2><h3 id="长期持有的税收优势" tabindex="-1">长期持有的税收优势 <a class="header-anchor" href="#长期持有的税收优势" aria-label="Permalink to &quot;长期持有的税收优势&quot;">​</a></h3><ul><li>极端例子：1元投资每年翻倍20年</li><li>持有不动：最终$680,000（税后）</li><li>每年卖出再买：最终$25,000</li><li>差距来自时间价值</li></ul><h3 id="真正的税负" tabindex="-1">真正的税负 <a class="header-anchor" href="#真正的税负" aria-label="Permalink to &quot;真正的税负&quot;">​</a></h3><ul><li>1989年缴纳所得税7.12亿美元</li><li>五大持仓对应未缴税约1.75亿美元</li></ul><hr><h2 id="非保险运营-七圣人和一个" tabindex="-1">非保险运营：七圣人和一个 <a class="header-anchor" href="#非保险运营-七圣人和一个" aria-label="Permalink to &quot;非保险运营：七圣人和一个&quot;">​</a></h2><h3 id="_1-borsheim-s珠宝" tabindex="-1">1. Borsheim&#39;s珠宝 <a class="header-anchor" href="#_1-borsheim-s珠宝" aria-label="Permalink to &quot;1. Borsheim&#39;s珠宝&quot;">​</a></h3><ul><li>销售额大幅增长（四年前搬新址后翻倍）</li><li>低成本、大库存、低价格、高流量</li><li>Ike Friedman管理天才</li></ul><h3 id="_2-喜诗糖果" tabindex="-1">2. 喜诗糖果 <a class="header-anchor" href="#_2-喜诗糖果" aria-label="Permalink to &quot;2. 喜诗糖果&quot;">​</a></h3><ul><li>销量增长8%</li><li>广告投入增加，效果显著</li><li>查克·哈金斯管理出色</li></ul><h3 id="_3-内布拉斯加家具城" tabindex="-1">3. 内布拉斯加家具城 <a class="header-anchor" href="#_3-内布拉斯加家具城" aria-label="Permalink to &quot;3. 内布拉斯加家具城&quot;">​</a></h3><ul><li>销售额创纪录</li><li>B夫人（96岁）因分歧退休，新开地毯店</li><li>奥马哈地毯市场份额从67.7%增至75.3%</li></ul><h3 id="_4-水牛城新闻" tabindex="-1">4. 水牛城新闻 <a class="header-anchor" href="#_4-水牛城新闻" aria-label="Permalink to &quot;4. 水牛城新闻&quot;">​</a></h3><ul><li>三项表现优异： <ul><li>家庭渗透率第一</li><li>新闻版面比例最高（50.1%）</li><li>连续七年利润创纪录</li></ul></li></ul><h3 id="_5-fechheimer、kirby、世界图书等" tabindex="-1">5. Fechheimer、Kirby、世界图书等 <a class="header-anchor" href="#_5-fechheimer、kirby、世界图书等" aria-label="Permalink to &quot;5. Fechheimer、Kirby、世界图书等&quot;">​</a></h3><ul><li>稳健运营</li><li>赫尔德曼家族、拉尔夫·谢伊管理出色</li></ul><hr><h2 id="保险业务" tabindex="-1">保险业务 <a class="header-anchor" href="#保险业务" aria-label="Permalink to &quot;保险业务&quot;">​</a></h2><h3 id="行业困境" tabindex="-1">行业困境 <a class="header-anchor" href="#行业困境" aria-label="Permalink to &quot;行业困境&quot;">​</a></h3><ul><li>保费增长远低于10%（损失增长要求）</li><li>综合成本率持续恶化</li><li>&quot;承保周期&quot;概念已过时——卡特尔时代结束</li><li>产能过剩问题</li></ul><h3 id="伯克希尔策略" tabindex="-1">伯克希尔策略 <a class="header-anchor" href="#伯克希尔策略" aria-label="Permalink to &quot;伯克希尔策略&quot;">​</a></h3><ul><li>保费从10亿降至1.5亿（不写亏钱业务）</li><li>保留大量浮存金</li><li>巨灾再保险机会：愿意承担大风险</li></ul><h3 id="巨灾再保险" tabindex="-1">巨灾再保险 <a class="header-anchor" href="#巨灾再保险" aria-label="Permalink to &quot;巨灾再保险&quot;">​</a></h3><ul><li>最大承保能力2.5亿美元</li><li>可能一个季度亏损1.65亿（税后）</li><li>波动性可接受，长期有利</li></ul><hr><h2 id="可交易证券" tabindex="-1">可交易证券 <a class="header-anchor" href="#可交易证券" aria-label="Permalink to &quot;可交易证券&quot;">​</a></h2><h3 id="五大持仓" tabindex="-1">五大持仓 <a class="header-anchor" href="#五大持仓" aria-label="Permalink to &quot;五大持仓&quot;">​</a></h3><table tabindex="0"><thead><tr><th>公司</th><th>持股</th><th>成本(M)</th></tr></thead><tbody><tr><td>首都城市/ABC</td><td>3,000,000股</td><td>517.5</td></tr><tr><td>可口可乐</td><td>23,350,000股</td><td>1,023.9</td></tr><tr><td>GEICO</td><td>6,850,000股</td><td>45.7</td></tr><tr><td>华盛顿邮报</td><td>1,727,765股</td><td>9.7</td></tr></tbody></table><h3 id="可转换优先股投资" tabindex="-1">可转换优先股投资 <a class="header-anchor" href="#可转换优先股投资" aria-label="Permalink to &quot;可转换优先股投资&quot;">​</a></h3><ul><li>吉列：6.6亿美元，股息8.75%</li><li>美国航空：3.58亿美元，股息9.25%</li><li>冠军国际：3亿美元，股息9.25%</li></ul><hr><h2 id="_25年错误总结" tabindex="-1">25年错误总结 <a class="header-anchor" href="#_25年错误总结" aria-label="Permalink to &quot;25年错误总结&quot;">​</a></h2><h3 id="_1-买入伯克希尔控制权" tabindex="-1">1. 买入伯克希尔控制权 <a class="header-anchor" href="#_1-买入伯克希尔控制权" aria-label="Permalink to &quot;1. 买入伯克希尔控制权&quot;">​</a></h3><ul><li>明知纺织业无前途，却因便宜而买</li><li>&quot;烟蒂投资法&quot;的局限：时间是好生意的朋友，坏生意的敌人</li></ul><h3 id="_2-买入hochschild-kohn百货" tabindex="-1">2. 买入Hochschild Kohn百货 <a class="header-anchor" href="#_2-买入hochschild-kohn百货" aria-label="Permalink to &quot;2. 买入Hochschild Kohn百货&quot;">​</a></h3><ul><li>账面价值打折，但生意差</li><li>再好的人也救不了烂生意</li></ul><h3 id="_3-机构惯性-institutional-imperative" tabindex="-1">3. 机构惯性（Institutional Imperative） <a class="header-anchor" href="#_3-机构惯性-institutional-imperative" aria-label="Permalink to &quot;3. 机构惯性（Institutional Imperative）&quot;">​</a></h3><ul><li>企业像牛顿第一定律：原方向保持不变</li><li>资本支出、收购、跟风同行</li><li>明知不对也要做</li></ul><h3 id="_4-错失机会" tabindex="-1">4. 错失机会 <a class="header-anchor" href="#_4-错失机会" aria-label="Permalink to &quot;4. 错失机会&quot;">​</a></h3><ul><li>错过大机会比做错事亏大钱伤害更大</li><li>但能力圈外无法强求</li></ul><hr><h2 id="经典语录" tabindex="-1">经典语录 <a class="header-anchor" href="#经典语录" aria-label="Permalink to &quot;经典语录&quot;">​</a></h2><ol><li><p><strong>关于投资原则</strong>：</p><blockquote><p>&quot;好骑师骑好马才能赢，骑破马赢不了。&quot;</p></blockquote></li><li><p><strong>关于做生意</strong>：</p><blockquote><p>&quot;和你喜欢、信任、欣赏的人做生意才能成大事。&quot;</p></blockquote></li><li><p><strong>关于错误</strong>：</p><blockquote><p>&quot;时间是好生意的朋友，坏生意的敌人。&quot;</p></blockquote></li><li><p><strong>关于能力圈</strong>：</p><blockquote><p>&quot;能力圈外面，你没办法。&quot;</p></blockquote></li><li><p><strong>关于婚姻与投资</strong>：</p><blockquote><p>&quot;有钱了你也不会为了换老婆离婚。已经很好了，为什么换？&quot;</p></blockquote></li></ol><hr><h2 id="收购标准" tabindex="-1">收购标准 <a class="header-anchor" href="#收购标准" aria-label="Permalink to &quot;收购标准&quot;">​</a></h2><ol><li>大额收购，税后盈利至少1000万美元</li><li>证明持续盈利能力（不要预测、不要turnaround）</li><li>高ROE，负债少最好无负债</li><li>管理层在位（我们提供不了）</li><li>业务简单（太多技术我们不懂）</li><li>报价明确（不知道价格不谈）</li></ol><hr><h2 id="_1989年启示" tabindex="-1">1989年启示 <a class="header-anchor" href="#_1989年启示" aria-label="Permalink to &quot;1989年启示&quot;">​</a></h2><ol><li><strong>商业模式至关重要</strong>：好生意坐着就能赚钱，差生意再聪明也难</li><li><strong>管理层是关键</strong>：好马配好骑师</li><li><strong>税收优势</strong>：长期持有可创造巨大价值</li><li><strong>逆向思维</strong>：接受波动换取更高长期回报</li><li><strong>耐心等待</strong>：不做勉强的交易</li></ol>',70)])])}const b=a(r,[["render",o]]);export{c as __pageData,b as default};
